    schema = Schema(query=Query, mutation=MyMutation)
    result = schema.execute(''' mutation mymutation {
        createBlank(name:"Peter") {
            string
            integer
        }
    }
    ''')
    assert not result.errors
    assert result.data == {
        'createUser': {
